={{
`AND(
  OR(
    FIND("Hold", ARRAYJOIN({Status (from Booking)})) > 0,
    FIND("Held", ARRAYJOIN({Status (from Booking)})) > 0,
    FIND("Confirmed", ARRAYJOIN({Status (from Booking)})) > 0,
    FIND("Checked_In", ARRAYJOIN({Status (from Booking)})) > 0,
    FIND("Blocked", ARRAYJOIN({Status (from Booking)})) > 0
  ),
  IS_BEFORE({Assignment Start Date}, DATETIME_PARSE("${$('Get Booking').first().json.fields['Check Out']}")),
  IS_AFTER({Assignment End Date}, DATETIME_PARSE("${$('Get Booking').first().json.fields['Check In']}"))
)`
