parameters.jsCode:
const booking = $('Get Booking').first().json;
const bookingFields = booking.fields || booking;

const bedsRaw = $('Search Active Beds').all();
const assignmentsRaw = $('Search Existing Bed Assignments').all();
const roomsRaw = $('Search Rooms').all();

const bookingRecordId = booking.id;
const bookingPublicId = bookingFields['Booking ID'];
const checkIn = bookingFields['Check In'];
const checkOut = bookingFields['Check Out'];

const bookingSource = bookingFields['Booking Source'] || '';
const operatorName = bookingFields['Operator Name'] || '';
const blockType = bookingFields['Block Type'] || '';

const roomToBlockRaw = bookingFields['Room to Block'];
const roomToBlockRecordId = Array.isArray(roomToBlockRaw)
  ? roomToBlockRaw[0]
  : roomToBlockRaw || null;

// SAFE guest count handling.
// Do not treat 0 as valid.
const rawGuestCount =
  bookingFields['Guest Count'] !== undefined &&
  bookingFields['Guest Count'] !== null &&
  Number(bookingFields['Guest Count']) > 0
    ? bookingFields['Guest Count']
    : bookingFields['Guests'] !== undefined &&
      bookingFields['Guests'] !== null &&
      Number(bookingFields['Guests']) > 0
        ? bookingFields['Guests']
        : 1;

const guestCount = Math.max(1, Number(rawGuestCount));

const requestedRoomType = String(
  bookingFields['Requested Room Type'] ||
  bookingFields['Room Type'] ||
  'shared'
).toLowerCase();

function normalizeSelect(value, fallback = 'unknown') {
  return String(value || fallback)
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_');
}

const guestGenderGroup = normalizeSelect(
  bookingFields['Guest Gender / Group Type'],
  'unknown'
);

const roomPreference = normalizeSelect(
  bookingFields['Room Preference'] || requestedRoomType,
  requestedRoomType || 'shared'
);

const roomingNotes = String(
  bookingFields['Rooming Notes'] || ''
).trim();

function getLookupValue(value) {
  if (Array.isArray(value)) return value[0];
  return value;
}

function getLookupValues(value) {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null || value === '') return [];
  return [value];
}

function overlaps(aStart, aEnd, bStart, bEnd) {
  return String(aStart) < String(bEnd) && String(bStart) < String(aEnd);
}

function boolValue(value) {
  if (Array.isArray(value)) value = value[0];
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value === 1;
  if (typeof value === 'string') {
    return ['true', 'yes', '1', 'checked', '👍'].includes(value.toLowerCase());
  }
  return false;
}

function cleanKey(value) {
  return String(value || '').trim();
}

function addKey(set, value) {
  for (const v of getLookupValues(value)) {
    const key = cleanKey(v);
    if (key) set.add(key);
  }
}

function hasAnyKey(set, values) {
  return values
    .filter(Boolean)
    .map(cleanKey)
    .some(key => set.has(key));
}

function explicitlyWantsPrivate() {
  return [
    requestedRoomType,
    roomPreference
  ].some(value =>
    [
      'private',
      'private_room',
      'double',
      'family_room',
      'family',
      'couple_private'
    ].includes(String(value || '').toLowerCase())
  );
}

const wantsPrivate = explicitlyWantsPrivate();

function wantsFemalePlacement() {
  return (
    roomPreference === 'female_only' ||
    guestGenderGroup === 'female_group' ||
    guestGenderGroup === 'solo_female'
  );
}

function wantsMalePlacement() {
  return (
    roomPreference === 'male_only' ||
    guestGenderGroup === 'male_group' ||
    guestGenderGroup === 'solo_male'
  );
}

const femalePlacementRequested = wantsFemalePlacement();
const malePlacementRequested = wantsMalePlacement();

function getFieldAny(fields, names, fallback = null) {
  for (const name of names) {
    if (
      fields[name] !== undefined &&
      fields[name] !== null &&
      fields[name] !== ''
    ) {
      return fields[name];
    }
  }

  return fallback;
}

// Build room metadata from Search Rooms.
// Room strategy/priority comes from Rooms, not Beds.
const roomsByRecordId = {};
const roomsByRoomId = {};

for (const item of roomsRaw) {
  const fields = item.json.fields || item.json;

  const roomRecordId = item.json.id;
  const roomId = getLookupValue(fields['Room ID']) || fields['Room ID'] || '';

  const fillPriorityRaw = getFieldAny(fields, [
    'Fill Priority',
    'Fill Priority ',
    'Fill priority',
    'Fill priority '
  ], 50);

  const privatePriorityRaw = getFieldAny(fields, [
    'Private Priority',
    'Private Priority ',
    'Private priority',
    'Private priority '
  ], 50);

  const roomData = {
    record_id: roomRecordId,
    room_id: roomId,
    room_type: getLookupValue(fields['Room Type']) || fields['Room Type'] || '',
    capacity: Number(getLookupValue(fields['Capacity']) || 0),
    fill_priority: Number(getLookupValue(fillPriorityRaw) || 50),
    private_priority: Number(getLookupValue(privatePriorityRaw) || 50),
    gender_strategy: String(getLookupValue(fields['Gender Strategy']) || 'Flexible'),
    can_be_matrimonial: boolValue(fields['Can be Matrimonial']),
    often_used_by_operator: boolValue(fields['Often used By Operator']),
    active: boolValue(fields['Active']),
    fields
  };

  if (roomRecordId) {
    roomsByRecordId[roomRecordId] = roomData;
  }

  if (roomId) {
    roomsByRoomId[String(roomId)] = roomData;
  }
}

// Normalize all active beds first.
const allBeds = bedsRaw.map(item => {
  const fields = item.json.fields || item.json;

  const roomRecordId = Array.isArray(fields['Room'])
    ? fields['Room'][0]
    : fields['Room'];

  const roomIdFromBed = getLookupValue(fields['Room ID']);

  const roomMeta =
    roomsByRecordId[roomRecordId] ||
    roomsByRoomId[String(roomIdFromBed || '')] ||
    {};

  const roomId =
    roomMeta.room_id ||
    roomIdFromBed ||
    '';

  const bedId = getLookupValue(fields['Bed ID']) || fields['Bed ID'] || '';
  const bedLabel = fields['Bed Label'] || fields['Name'] || bedId || '';

  return {
    record_id: item.json.id,
    bed_id: bedId,
    room_record_id: roomRecordId,
    room_id: roomId,
    room_name:
      roomMeta.room_id ||
      getLookupValue(fields['Room Name']) ||
      getLookupValue(fields['Room']) ||
      '',
    bed_number: Number(fields['Bed Number'] || 0),
    bed_label: bedLabel,

    room_type: roomMeta.room_type || '',
    capacity: Number(roomMeta.capacity || 0),
    fill_priority: Number(roomMeta.fill_priority || 50),
    private_priority: Number(roomMeta.private_priority || 50),
    gender_strategy: String(roomMeta.gender_strategy || 'Flexible'),
    can_be_matrimonial: boolValue(roomMeta.can_be_matrimonial),
    often_used_by_operator: boolValue(roomMeta.often_used_by_operator),
    room_active: roomMeta.active !== false,

    fields
  };
}).filter(bed => bed.record_id && bed.room_id);

const bedToRoom = {};

for (const bed of allBeds) {
  const possibleBedKeys = [
    bed.record_id,
    bed.bed_id,
    bed.bed_label,
    bed.fields?.['Bed ID'],
    bed.fields?.['Bed Label'],
    bed.fields?.['Name']
  ].filter(Boolean);

  for (const key of possibleBedKeys) {
    bedToRoom[cleanKey(key)] = bed.room_id;
  }
}

// Existing occupied beds and room occupancy.
const occupiedBedKeys = new Set();
const occupiedByRoom = {};
const genderByRoom = {};

for (const item of assignmentsRaw) {
  const a = item.json.fields || item.json;

  const aStart =
    getLookupValue(a['Assignment Start Date']) ||
    getLookupValue(a['Check In']);

  const aEnd =
    getLookupValue(a['Assignment End Date']) ||
    getLookupValue(a['Check Out']);

  const assignmentOverlaps =
    !aStart || !aEnd || overlaps(checkIn, checkOut, aStart, aEnd);

  if (!assignmentOverlaps) continue;

  addKey(occupiedBedKeys, a['Bed']);
  addKey(occupiedBedKeys, a['Bed ID']);
  addKey(occupiedBedKeys, a['Bed Label']);
  addKey(occupiedBedKeys, a['Bed Name']);
  addKey(occupiedBedKeys, a['Bed Key']);
  addKey(occupiedBedKeys, a['Name']);

  const possibleAssignmentBedKeys = [
    ...getLookupValues(a['Bed']),
    ...getLookupValues(a['Bed ID']),
    ...getLookupValues(a['Bed Label']),
    ...getLookupValues(a['Bed Name']),
    ...getLookupValues(a['Bed Key']),
    ...getLookupValues(a['Name'])
  ].filter(Boolean).map(cleanKey);

  const roomId =
    getLookupValue(a['Room ID']) ||
    getLookupValue(a['Room']) ||
    possibleAssignmentBedKeys.map(key => bedToRoom[key]).find(Boolean);

  if (roomId) {
    occupiedByRoom[roomId] = (occupiedByRoom[roomId] || 0) + 1;

    const gender =
      normalizeSelect(
        a['Guest Gender / Group Type'] ||
        a['Gender Group'] ||
        a['gender_group'] ||
        '',
        ''
      );

    if (gender) {
      if (!genderByRoom[roomId]) genderByRoom[roomId] = new Set();
      genderByRoom[roomId].add(gender);
    }
  }
}

// Free beds only.
const freeBeds = allBeds.filter(bed => {
  const possibleKeys = [
    bed.record_id,
    bed.bed_id,
    bed.bed_label,
    bed.fields?.['Bed ID'],
    bed.fields?.['Bed Label'],
    bed.fields?.['Name']
  ];

  const isOccupied = hasAnyKey(occupiedBedKeys, possibleKeys);

  return bed.record_id && !isOccupied;
});

// CASE 1: Operator whole-room block.
const isOperatorWholeRoomBlock =
  bookingSource === 'Operator' &&
  blockType === 'Whole Room' &&
  !!roomToBlockRecordId;

if (isOperatorWholeRoomBlock) {
  const roomBeds = freeBeds
    .filter(bed => String(bed.room_record_id) === String(roomToBlockRecordId))
    .sort((a, b) => a.bed_number - b.bed_number);

  if (roomBeds.length === 0) {
    return [{
      json: {
        booking_record_id: bookingRecordId,
        booking_id: bookingPublicId,
        guest_count: guestCount,
        assignment_status: 'Needs Review',
        availability_check_status: 'Conflict',
        conflict_notes: `No free beds found in the selected room for ${operatorName || 'operator'} from ${checkIn} to ${checkOut}.`,
        selected_beds: [],
        gender_group: 'operator_group',
        room_preference: 'unknown',
        rooming_notes: `${operatorName || 'Operator'} whole-room block`
      }
    }];
  }

  return roomBeds.map(bed => ({
    json: {
      booking_record_id: bookingRecordId,
      booking_id: bookingPublicId,
      guest_count: guestCount,
      bed_record_id: bed.record_id,
      bed_id: bed.bed_id,
      room_id: bed.room_id,
      room_name: bed.room_name,
      check_in: checkIn,
      check_out: checkOut,
      requested_room_type: 'operator_block',
      assignment_status: 'Assigned',
      availability_check_status: 'Available',
      conflict_notes: '',
      assignment_type: 'Manual Staff Assignment',
      gender_group: 'operator_group',
      room_preference: 'unknown',
      rooming_notes: `${operatorName || 'Operator'} whole-room block`,
      notes: `${operatorName || 'Operator'} whole-room block`
    }
  }));
}

// Build rooms from free beds.
const rooms = {};

for (const bed of freeBeds) {
  if (!rooms[bed.room_id]) {
    rooms[bed.room_id] = {
      room_id: bed.room_id,
      room_name: bed.room_name,
      room_type: bed.room_type,
      capacity: bed.capacity,
      fill_priority: bed.fill_priority,
      private_priority: bed.private_priority,
      gender_strategy: bed.gender_strategy,
      can_be_matrimonial: bed.can_be_matrimonial,
      often_used_by_operator: bed.often_used_by_operator,
      occupied_count: occupiedByRoom[bed.room_id] || 0,
      existing_gender_groups: Array.from(genderByRoom[bed.room_id] || []),
      beds: []
    };
  }

  rooms[bed.room_id].beds.push(bed);
}

for (const room of Object.values(rooms)) {
  room.beds.sort((a, b) => a.bed_number - b.bed_number);
}

const roomList = Object.values(rooms)
  .filter(room => room.beds.length > 0);

function roomGenderStrategy(room) {
  return String(room.gender_strategy || 'Flexible').trim().toLowerCase();
}

function roomTypeValue(room) {
  return String(room.room_type || '').trim().toLowerCase();
}

function roomIsFemalePreferred(room) {
  const genderStrategy = roomGenderStrategy(room);

  return (
    genderStrategy.includes('female') ||
    genderStrategy.includes('women') ||
    genderStrategy.includes('woman') ||
    genderStrategy.includes('ladies') ||
    genderStrategy.includes('girls')
  );
}

function roomIsMalePreferred(room) {
  const genderStrategy = roomGenderStrategy(room);

  return (
    genderStrategy.includes('male') ||
    genderStrategy.includes('men') ||
    genderStrategy.includes('man') ||
    genderStrategy.includes('boys')
  );
}

function roomIsMixedOrFlexible(room) {
  const genderStrategy = roomGenderStrategy(room);

  return (
    genderStrategy.includes('mixed') ||
    genderStrategy.includes('flexible') ||
    genderStrategy === ''
  );
}

function isPrivateLikeRoom(room) {
  const strategy = roomGenderStrategy(room);
  const type = roomTypeValue(room);

  // Important:
  // Can be Matrimonial does NOT make a room private-like.
  // R3 can be matrimonial but should still be usable first for normal shared bookings.
  return (
    strategy.includes('private') ||
    type.includes('private') ||
    type.includes('double') ||
    type.includes('family') ||
    Number(room.capacity) === 2
  );
}

function roomHardBlocked(room) {
  const genderStrategy = roomGenderStrategy(room);

  if (genderStrategy.includes('operator')) {
    return bookingSource !== 'Operator';
  }

  if (genderStrategy.includes('female only')) {
    return !['solo_female', 'female_group'].includes(guestGenderGroup);
  }

  if (genderStrategy.includes('male only')) {
    return !['solo_male', 'male_group'].includes(guestGenderGroup);
  }

  return false;
}

function roomBaseScore(room, guestsAssignedToRoom) {
  let score = 0;

  const genderStrategy = roomGenderStrategy(room);

  // Base room priority from Rooms table.
  // Bigger multiplier makes Fill Priority the main normal-placement driver.
  if (wantsPrivate) {
    score += Number(room.private_priority || 50) * 100;
  } else {
    score += Number(room.fill_priority || 50) * 100;
  }

  // Reserve gender-preferred rooms unless the guest needs that placement.
  if (!femalePlacementRequested && roomIsFemalePreferred(room)) {
    score += 900;
  }

  if (!malePlacementRequested && roomIsMalePreferred(room)) {
    score += 900;
  }

  // Do not use genuinely private/double/family rooms for normal shared bookings unless explicitly requested.
  if (isPrivateLikeRoom(room) && !wantsPrivate) {
    score += 10000;
  }

  // If private was requested, strongly prefer private-like rooms.
  if (isPrivateLikeRoom(room) && wantsPrivate) {
    score -= 120;
  }

  // Operator rooms later unless needed.
  if (room.often_used_by_operator && bookingSource !== 'Operator') {
    score += 40;
  }

  // Keep R4 / 9-bed room later unless it makes sense for a big group.
  if (room.room_id === 'R4') {
    score += guestCount >= 7 ? 20 : 120;
  }

  // Spread the house: rooms already occupied get a penalty.
  score += Number(room.occupied_count || 0) * 12;

  // Gender strategy matching.
  if (guestGenderGroup === 'female_group' || guestGenderGroup === 'solo_female') {
    if (roomIsFemalePreferred(room)) score -= 500;
    if (roomIsMalePreferred(room)) score += 1000;
    if (roomIsMixedOrFlexible(room)) score += 80;
  }

  if (guestGenderGroup === 'male_group' || guestGenderGroup === 'solo_male') {
    if (roomIsMalePreferred(room)) score -= 500;
    if (roomIsFemalePreferred(room)) score += 1000;
    if (roomIsMixedOrFlexible(room)) score += 80;
  }

  if (
    guestGenderGroup === 'mixed_group' ||
    guestGenderGroup === 'couple' ||
    guestGenderGroup === 'family'
  ) {
    if (genderStrategy.includes('mixed')) score -= 25;
    if (genderStrategy.includes('flexible')) score -= 10;
  }

  // Existing room composition.
  const existing = room.existing_gender_groups || [];

  if (existing.length) {
    if (['solo_female', 'female_group'].includes(guestGenderGroup)) {
      if (existing.every(g => g.includes('female'))) score -= 120;
      if (existing.some(g => g.includes('male'))) score += 500;
    }

    if (['solo_male', 'male_group'].includes(guestGenderGroup)) {
      if (existing.every(g => g.includes('male'))) score -= 120;
      if (existing.some(g => g.includes('female'))) score += 500;
    }
  }

  // Room preference matching.
  if (roomPreference === 'female_only') {
    if (roomIsFemalePreferred(room)) score -= 1000;
    if (roomIsMalePreferred(room)) score += 2000;
    if (roomIsMixedOrFlexible(room)) score += 300;
  }

  if (roomPreference === 'male_only') {
    if (roomIsMalePreferred(room)) score -= 1000;
    if (roomIsFemalePreferred(room)) score += 2000;
    if (roomIsMixedOrFlexible(room)) score += 300;
  }

  if (roomPreference === 'mixed_ok' || roomPreference === 'any') {
    if (genderStrategy.includes('mixed') || genderStrategy.includes('flexible')) score -= 15;
  }

  // Only give matrimonial/private boost if private/double was explicitly requested.
  if (roomPreference === 'double' || wantsPrivate) {
    if (room.can_be_matrimonial) score -= 30;
    if (!room.can_be_matrimonial && wantsPrivate) score += 20;
  }

  // Tetris leftover scoring.
  const leftoverAfterThisBooking = room.beds.length - guestsAssignedToRoom;

  if (leftoverAfterThisBooking === 0) {
    score -= 25;
  } else if (leftoverAfterThisBooking === 1) {
    score += 35;
  } else if (leftoverAfterThisBooking === 2) {
    score -= 5;
  }

  // Prefer putting more of the group in each used room.
  score -= guestsAssignedToRoom * 4;

  return score;
}

function distributeGuestsAcrossRooms(combo, totalGuests) {
  let remaining = totalGuests;
  const allocation = [];

  const sorted = [...combo].sort((a, b) => {
    return roomBaseScore(a, Math.min(a.beds.length, remaining)) -
      roomBaseScore(b, Math.min(b.beds.length, remaining));
  });

  for (const room of sorted) {
    if (remaining <= 0) break;

    const assignCount = Math.min(room.beds.length, remaining);

    allocation.push({
      room,
      assign_count: assignCount
    });

    remaining -= assignCount;
  }

  return {
    allocation,
    remaining
  };
}

function comboScore(combo) {
  const totalFreeBeds = combo.reduce((sum, room) => sum + room.beds.length, 0);

  if (totalFreeBeds < guestCount) return Infinity;
  if (combo.some(roomHardBlocked)) return Infinity;

  const { allocation, remaining } = distributeGuestsAcrossRooms(combo, guestCount);
  if (remaining > 0) return Infinity;

  let score = 0;

  // Fewer rooms is better for guest.
  score += (allocation.length - 1) * 75;

  // Big groups are expected to split.
  if (guestCount >= 8) {
    score -= 20;
  }

  for (const part of allocation) {
    score += roomBaseScore(part.room, part.assign_count);
  }

  const totalLeftover = totalFreeBeds - guestCount;
  score += totalLeftover * 3;

  if (allocation.length >= 3) score += 20;

  return score;
}

function generateRoomCombos(roomList) {
  const combos = [];

  function backtrack(start, combo) {
    if (combo.length > 0) combos.push([...combo]);

    for (let i = start; i < roomList.length; i++) {
      combo.push(roomList[i]);
      backtrack(i + 1, combo);
      combo.pop();
    }
  }

  backtrack(0, []);
  return combos;
}

const baseUsableRooms = roomList.filter(room => !roomHardBlocked(room));

let usableRooms = baseUsableRooms;

// If the guest specifically needs female-only placement,
// first restrict to female-preferred rooms if there are enough beds there.
if (roomPreference === 'female_only') {
  const femalePreferredRooms = baseUsableRooms.filter(room => roomIsFemalePreferred(room));

  const femalePreferredFreeBeds = femalePreferredRooms.reduce(
    (sum, room) => sum + room.beds.length,
    0
  );

  if (femalePreferredFreeBeds >= guestCount) {
    usableRooms = femalePreferredRooms;
  } else {
    usableRooms = baseUsableRooms.filter(room =>
      !roomIsMalePreferred(room)
    );
  }
}

// Same idea for male-only placement.
if (roomPreference === 'male_only') {
  const malePreferredRooms = baseUsableRooms.filter(room => roomIsMalePreferred(room));

  const malePreferredFreeBeds = malePreferredRooms.reduce(
    (sum, room) => sum + room.beds.length,
    0
  );

  if (malePreferredFreeBeds >= guestCount) {
    usableRooms = malePreferredRooms;
  } else {
    usableRooms = baseUsableRooms.filter(room =>
      !roomIsFemalePreferred(room)
    );
  }
}

// Failsafe: if filtering leaves no usable rooms, fall back to base rooms.
if (!usableRooms.length) {
  usableRooms = baseUsableRooms;
}

// First, try one room.
const oneRoomCandidates = usableRooms
  .filter(room => room.beds.length >= guestCount)
  .map(room => ({
    rooms: [room],
    score: roomBaseScore(room, guestCount),
    allocation: [{ room, assign_count: guestCount }]
  }))
  .sort((a, b) => a.score - b.score);

let selectedPlan = oneRoomCandidates[0] || null;

// If no single room fits, use multi-room Tetris.
if (!selectedPlan) {
  const combos = generateRoomCombos(usableRooms)
    .filter(combo => combo.length >= 2)
    .map(combo => {
      const score = comboScore(combo);
      const { allocation, remaining } = distributeGuestsAcrossRooms(combo, guestCount);

      return {
        rooms: combo,
        score,
        allocation,
        remaining
      };
    })
    .filter(plan => Number.isFinite(plan.score) && plan.remaining === 0)
    .sort((a, b) => a.score - b.score);

  selectedPlan = combos[0] || null;
}

if (!selectedPlan) {
  return [{
    json: {
      booking_record_id: bookingRecordId,
      booking_id: bookingPublicId,
      guest_count: guestCount,
      assignment_status: 'Needs Review',
      availability_check_status: 'Conflict',
      conflict_notes: `Could not find enough suitable free beds for ${guestCount} guest(s) from ${checkIn} to ${checkOut}. Occupied keys found: ${Array.from(occupiedBedKeys).join(', ')}`,
      selected_beds: [],
      gender_group: guestGenderGroup,
      room_preference: roomPreference,
      rooming_notes: roomingNotes
    }
  }];
}

const output = [];

for (const part of selectedPlan.allocation) {
  const room = part.room;
  const selectedBeds = room.beds.slice(0, part.assign_count);

  for (const bed of selectedBeds) {
    output.push({
      json: {
        booking_record_id: bookingRecordId,
        booking_id: bookingPublicId,
        guest_count: guestCount,
        bed_record_id: bed.record_id,
        bed_id: bed.bed_id,
        room_id: bed.room_id,
        room_name: bed.room_name,
        check_in: checkIn,
        check_out: checkOut,
        requested_room_type: requestedRoomType,
        assignment_status: 'Assigned',
        availability_check_status: 'Available',
        conflict_notes: '',
        assignment_type: selectedPlan.allocation.length > 1
          ? 'Auto Assigned - Multi Room'
          : 'Auto Assigned',

        gender_group: guestGenderGroup || 'unknown',
        room_preference: roomPreference || 'unknown',
        rooming_notes: roomingNotes,

        notes:
          `Auto-assigned by Booking Agent. ` +
          `Guest count: ${guestCount}. ` +
          `Plan score: ${selectedPlan.score}. ` +
          `Room: ${room.room_id}. ` +
          `Room gender strategy: ${room.gender_strategy}. ` +
          `Room fill priority: ${room.fill_priority}. ` +
          `Can be matrimonial: ${room.can_be_matrimonial}. ` +
          `Bed: ${bed.bed_id}. ` +
          `Private requested: ${wantsPrivate}. ` +
          `Gender/group: ${guestGenderGroup || 'unknown'}. ` +
          `Preference: ${roomPreference || 'unknown'}.`
      }
    });
  }
}

return output;

const items = $('Code - Choose Beds').all();
const beds = [];
for (const item of items) {
  const j = item.json || {};
  if (!j.bed_id && !j.bed_record_id) continue;
  const bedCode = String(j.bed_id || '').trim().toUpperCase();
  if (!bedCode) continue;
  beds.push({
    bed_code: bedCode,
    assignment_start_date: j.check_in,
    assignment_end_date: j.check_out,
    assignment_type: j.assignment_type || 'Auto Assigned'
  });
}
const parsed = $('Code - Parse Assign Webhook').first().json;
const booking = $('Get Booking').first().json;
const fields = booking.fields || booking;
const bookingCode = fields['Booking ID'] || parsed.booking_code || '';
return [{
  json: {
    beds_json: JSON.stringify(beds),
    beds_count: beds.length,
    airtable_record_id: parsed.airtable_record_id,
    booking_code: bookingCode,
    record_id: parsed.record_id || parsed.airtable_record_id
  }
}];

const parsed = $('Code - Parse Assign Webhook').first().json;
const pgItems = $('Postgres - Assign Beds In Postgres').all();
const pgItem = pgItems[0];
const pgErr = pgItem?.error;
const pg = pgItem?.json || {};

if (pgErr) {
  const msg = String(pgErr.message || pgErr);
  return [{
    json: {
      pg_ok: false,
      errors: [msg.includes('no parameter') ? 'postgres_query_param_missing' : 'postgres_assign_failed'],
      record_id: parsed.record_id,
      booking_code: parsed.booking_code,
      pg_inserted_count: 0,
      pg_skipped_count: 0,
      pg_conflict_count: 0,
      partial_failure: 'pg_query_failed',
      message: msg
    }
  }];
}

const resolved = Number(pg.booking_rows_resolved ?? 0);
const errors = [];

if (resolved !== 1) {
  errors.push(resolved === 0 ? 'booking_not_found_in_postgres' : 'booking_ambiguous_in_postgres');
}
if (Number(pg.pg_unknown_count ?? 0) > 0) {
  errors.push('unknown_bed_codes_in_postgres');
}
if (Number(pg.pg_conflict_count ?? 0) > 0) {
  errors.push('postgres_overlap_conflicts');
}
const before = String(pg.payment_status_before || '');
const after = String(pg.payment_status_after || '');
if (before && after && before !== after) {
  errors.push('payment_status_changed_during_pg_assign');
}
if (Number(pg.payments_count_before ?? 0) !== Number(pg.payments_count_after ?? 0)) {
  errors.push('payments_count_changed_during_pg_assign');
}

const pgOk = pg.pg_ok === true && errors.length === 0;

return [{
  json: {
    pg_ok: pgOk,
    errors,
    ...pg,
    record_id: parsed.record_id || parsed.airtable_record_id,
    booking_code: pg.booking_code || parsed.booking_code,
    pg_inserted_count: Number(pg.pg_inserted_count ?? 0),
    pg_skipped_count: Number(pg.pg_skipped_count ?? 0),
    pg_conflict_count: Number(pg.pg_conflict_count ?? 0),
    partial_failure: pgOk ? null : (Number(pg.pg_conflict_count) > 0 ? 'postgres_overlap_conflicts' : 'pg_assign_failed'),
    message: pgOk ? 'postgres_assign_ok' : errors.join('; ')
  }
}];

const parsed = $('Code - Parse Assign Webhook').first().json;
const chosen = $('Code - Choose Beds').all();
const creates = $('Create Booking Bed Assignment').all();
const pairs = [];

for (const createItem of creates) {
  if (createItem.error) continue;
  const atId = createItem.json?.id;
  if (!atId) continue;
  const bedRec = createItem.json?.fields?.Bed;
  const bedRecordId = Array.isArray(bedRec) ? bedRec[0] : bedRec;
  const match = chosen.find((c) => c.json?.bed_record_id === bedRecordId);
  const bedCode = String(match?.json?.bed_id || '').trim().toUpperCase();
  if (!bedCode) continue;
  pairs.push({ bed_code: bedCode, airtable_record_id: atId });
}

return [{
  json: {
    pairs_json: JSON.stringify(pairs),
    pair_count: pairs.length,
    airtable_record_id: parsed.airtable_record_id,
    booking_code: $('Code - Build PG Beds JSON').first().json.booking_code || parsed.booking_code,
    record_id: parsed.record_id || parsed.airtable_record_id
  }
}];

function mergeErrors(...lists) {
  const out = [];
  for (const list of lists) {
    if (!list) continue;
    for (const e of list) {
      const s = String(e || '').trim();
      if (s && !out.includes(s)) out.push(s);
    }
  }
  return out;
}

const parsed = $('Code - Parse Assign Webhook').first()?.json || {};
const record_id = parsed.record_id || parsed.airtable_record_id || '';

if (!parsed.parse_ok) {
  return [{
    json: {
      ok: false,
      booking_code: parsed.booking_code || '',
      record_id,
      pg_inserted_count: 0,
      pg_skipped_count: 0,
      pg_conflict_count: 0,
      airtable_create_ok: false,
      airtable_update_ok: false,
      partial_failure: 'parse_failed',
      idempotent: false,
      errors: mergeErrors(parsed.errors, ['parse_failed']),
      skipped_reason: null,
      message: 'Invalid webhook payload'
    }
  }];
}

let needsAssign = true;
try {
  const ifNeeds = $('IF - Needs Bed Assignment').first();
  needsAssign = !!ifNeeds;
} catch (e) {}

let chooseBedsRan = false;
try {
  chooseBedsRan = $('Code - Choose Beds').all().length > 0;
} catch (e) {}

let skippedReason = null;
if (!chooseBedsRan) {
  try {
    const booking = $('Get Booking').first()?.json;
    const fields = booking?.fields || booking || {};
    const status = fields['Assignment Status'];
    if (['Assigned', 'Assigning', 'Needs Review'].includes(status)) {
      skippedReason = 'already_assigned_or_ineligible';
    }
    if (['Cancelled', 'Expired'].includes(fields['Status'])) {
      skippedReason = 'booking_cancelled_or_expired';
    }
  } catch (e) {}
}

let conflictBranch = false;
try {
  const conflictIf = $('IF - Bed Assignment Conflict').first();
  const chooseFirst = $('Code - Choose Beds').first()?.json || {};
  conflictBranch =
    chooseFirst.assignment_status === 'Needs Review' ||
    chooseFirst.availability_check_status === 'Conflict';
} catch (e) {}

if (skippedReason) {
  return [{
    json: {
      ok: false,
      booking_code: parsed.booking_code || '',
      record_id,
      pg_inserted_count: 0,
      pg_skipped_count: 0,
      pg_conflict_count: 0,
      airtable_create_ok: false,
      airtable_update_ok: false,
      partial_failure: null,
      idempotent: true,
      errors: [],
      skipped_reason: skippedReason,
      message: 'assign_skipped_' + skippedReason
    }
  }];
}

if (conflictBranch) {
  let pgConflict = {};
  try { pgConflict = $('Postgres - Mirror Assignment Conflict').first()?.json || {}; } catch (e) {}
  let atUpd = null;
  try { atUpd = $('Update Booking Assignment Status - Conflict').first(); } catch (e) {}
  const atUpdateOk = !!(atUpd?.json?.id || atUpd?.json?.fields) && !atUpd?.error;
  return [{
    json: {
      ok: atUpdateOk,
      booking_code: pgConflict.booking_code || parsed.booking_code || '',
      record_id,
      pg_inserted_count: 0,
      pg_skipped_count: 0,
      pg_conflict_count: 1,
      airtable_create_ok: false,
      airtable_update_ok: atUpdateOk,
      partial_failure: atUpdateOk ? null : 'pg_ok_airtable_failed',
      idempotent: false,
      errors: mergeErrors(atUpd?.error ? [String(atUpd.error.message || atUpd.error)] : []),
      skipped_reason: null,
      assignment_conflict: true,
      message: 'assignment_conflict'
    }
  }];
}

let validate = { pg_ok: false, errors: ['validate_pg_assign_not_run'] };
try {
  validate = $('Code - Validate PG Assign').first().json;
} catch (e) {}

const pgInserted = Number(validate.pg_inserted_count ?? 0);
const pgSkipped = Number(validate.pg_skipped_count ?? 0);
const pgConflict = Number(validate.pg_conflict_count ?? 0);

if (!validate.pg_ok) {
  return [{
    json: {
      ok: false,
      booking_code: validate.booking_code || parsed.booking_code || '',
      record_id: validate.record_id || record_id,
      pg_inserted_count: pgInserted,
      pg_skipped_count: pgSkipped,
      pg_conflict_count: pgConflict,
      airtable_create_ok: false,
      airtable_update_ok: false,
      partial_failure: validate.partial_failure || 'pg_failed',
      idempotent: pgInserted === 0 && pgSkipped > 0,
      errors: mergeErrors(validate.errors, [validate.message]),
      skipped_reason: null,
      message: validate.message || 'Postgres assign did not complete — Airtable steps skipped'
    }
  }];
}

let createItems = [];
let upd = null;
try { createItems = $('Create Booking Bed Assignment').all(); } catch (e) {}
try { upd = $('Update Booking Assignment Status').first(); } catch (e) {}

const atCreateErrors = [];
let atCreateAttempts = 0;
for (const item of createItems) {
  if (item.error) {
    atCreateErrors.push(String(item.error.message || item.error));
    continue;
  }
  if (item.json?.id) atCreateAttempts += 1;
}

const atCreateOk = atCreateErrors.length === 0 && atCreateAttempts > 0;
const atUpdateOk = !!(upd?.json?.id || upd?.json?.fields) && !upd?.error;

let partial_failure = null;
if (validate.pg_ok && !atCreateOk) partial_failure = 'pg_ok_airtable_failed';
if (!validate.pg_ok && atCreateOk) partial_failure = 'pg_failed_airtable_ok';

const idempotent = pgInserted === 0 && (pgSkipped > 0 || atCreateAttempts === 0);

return [{
  json: {
    ok: validate.pg_ok && atCreateOk && atUpdateOk && !partial_failure,
    booking_code: validate.booking_code || parsed.booking_code,
    record_id: validate.record_id || record_id,
    pg_inserted_count: pgInserted,
    pg_skipped_count: pgSkipped,
    pg_conflict_count: pgConflict,
    airtable_create_ok: atCreateOk,
    airtable_update_ok: atUpdateOk,
    partial_failure,
    idempotent,
    errors: mergeErrors(validate.errors, atCreateErrors),
    skipped_reason: null,
    message:
      partial_failure === 'pg_ok_airtable_failed'
        ? 'Postgres assign succeeded; Airtable step failed'
        : idempotent
          ? 'assign_beds_idempotent'
          : 'assign_beds_complete'
  }
}];
